import org.owasp.encoder.Encode;

import java.io.File;
import java.io.FileWriter;
import java.io.IOException;

public class XSSFixedCode {

    public static void main(String[] args) {
        // Simulating user input (which could come from a form submission)
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Properly encoding user input before including it in the output HTML
        String encodedUserInput = Encode.forHtml(userInput);
        String output = "<p>Welcome, " + encodedUserInput + "</p>";

        try {
            // Outputting the safe data to the client
            File file = new File("output.html");
            FileWriter writer = new FileWriter(file);
            writer.write(output);
            writer.close();

            System.out.println("Output successfully written to output.html");
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
